#include <bits/stdc++.h>
using namespace std;
#define int long long
#define inf INT_MAX
using pii=pair<int,int>;
using piii=pair<int,pii>;
const int maxn=1e4+5,maxk=12;
int n,m,k,s,t;
struct node {
	vector<pii>e;
	int d[maxk];
} v[maxn];
priority_queue<piii,vector<piii>,greater<piii>> pq;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m>>k>>s>>t;
	s++,t++;
	for(int i=1,x,y,z; i<=m; i++) {
		cin>>x>>y>>z;
		x++,y++;
		v[x].e.emplace_back(z,y);
		v[y].e.emplace_back(z,x);
	}
	for(int i=1; i<=n; i++) {
		fill(v[i].d,v[i].d+1+k,inf);
	}
	for(pq.push({0,{0,s}}); pq.size();) {
		auto p=pq.top();
		pq.pop();
		if(p.second.first<=k&&v[p.second.second].d[p.second.first]==inf){
			v[p.second.second].d[p.second.first]=p.first;
			for(auto x:v[p.second.second].e){
				pq.push({p.first,{p.second.first+1,x.second}});
				pq.push({p.first+x.first,{p.second.first,x.second}});
			}
		}
	}
	sort(v[t].d,v[t].d+1+k);
	cout<<v[t].d[0];
	return 0;
}
